const axios = require('axios');
const cheerio = require('cheerio');

async function getMetadata(url) {
  try {
    const response = await axios.get(url);
    if (response.status === 200) {
      const $ = cheerio.load(response.data);
      const metaTags = $('meta');
      const title = $('title').text();
      const description = '';

      for (let i = 0; i < metaTags.length; i++) {
        const tag = $(metaTags[i]);
        if (tag.attr('property') === 'og:title' || tag.attr('name') === 'twitter:title') {
          title = tag.attr('content');
        } else if (tag.attr('property') === 'og:description' || tag.attr('name') === 'twitter:description') {
          description = tag.attr('content');
        }
      }

      return { url, title, description };
    } else {
      console.log(`Error fetching metadata: ${response.statusText}`);
    }
  } catch (error) {
    console.error(`Error fetching metadata: ${error.message}`);
  }
}

exports.getMetadata = getMetadata;